1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	type StepResult = { premium: number };
7	type ScenarioResult = { results: StepResult[] };
8	
9	const BASE_PRICES: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_SIZE = 3;
22	const BLOCK_PRICE = 60;
23	
24	const groupByType = (items: Item[]): Map<string, Item[]> => {
25	  const groups = new Map<string, Item[]>();
26	  for (const item of items) {
27	    const existing = groups.get(item.type) ?? [];
28	    existing.push(item);
29	    groups.set(item.type, existing);
30	  }
31	  return groups;
32	};
33	
34	const groupBasePrice = (type: string, members: Item[]): number => {
35	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
36	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
37	};
38	
39	const sumBasePrices = (items: Item[]): number => {
40	  let total = 0;
41	  for (const [type, members] of groupByType(items)) {
42	    total += groupBasePrice(type, members);
43	  }
44	  return total;
45	};
46	
47	const quotePremium = (items: Item[]): number =>
48	  sumBasePrices(items) + PROCESSING_FEE;
49	
50	const runStep = (step: QuoteStep): StepResult => ({
51	  premium: quotePremium(step.items),
52	});
53	
54	export const runScenario = (input: Scenario): ScenarioResult => ({
55	  results: input.steps.map(runStep),
56	});
